const item = $input.first();
const aiContent = item.json.content || item.json.text || item.json.message?.content || '';

let parsed = {};
try {
  // Strip markdown code fences if present
  const cleaned = aiContent
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Safe fallback if JSON parse fails
  parsed = {
    overall_score: 5,
    recommendation: 'Maybe',
    match_percentage: 50,
    summary: 'AI parsing error — please review this resume manually.',
    key_strengths: ['Could not extract'],
    skill_gaps: ['Could not extract'],
    red_flags: ['Parse error — manual review required'],
    years_of_experience: 'Unknown',
    education_fit: 'Unknown',
    culture_fit_score: 5,
    interview_questions: ['Please review resume manually'],
    estimated_salary: 'Unknown',
    standout_factor: 'Parse error — check raw_ai_response field',
    next_action: 'On Hold'
  };
}

return [{
  json: {
    // Candidate info (passed through)
    candidate_name:    item.json.candidate_name,
    candidate_email:   item.json.candidate_email,
    position:          item.json.position,
    company:           item.json.company,
    hr_email:          item.json.hr_email,
    screened_at:       item.json.screened_at,

    // AI screening results
    overall_score:     parsed.overall_score     ?? 5,
    recommendation:    parsed.recommendation    ?? 'Maybe',
    match_percentage:  parsed.match_percentage  ?? 50,
    summary:           parsed.summary           ?? '',
    key_strengths:     (parsed.key_strengths    || []).join(', '),
    skill_gaps:        (parsed.skill_gaps       || []).join(', '),
    red_flags:         (parsed.red_flags        || []).join(', '),
    years_of_experience: parsed.years_of_experience ?? '',
    education_fit:     parsed.education_fit     ?? '',
    culture_fit_score: parsed.culture_fit_score ?? 5,
    interview_questions: (parsed.interview_questions || []).join(' | '),
    estimated_salary:  parsed.estimated_salary  ?? '',
    standout_factor:   parsed.standout_factor   ?? '',
    next_action:       parsed.next_action       ?? 'On Hold',

    // Keep raw response for debugging
    raw_ai_response: aiContent.substring(0, 500)
  }
}];

